97	export async function fetchJobs(
98	  page: number = 1,
99	  pageSize: number = 100,
100	  filters?: JobListFilters
101	): Promise<PaginatedResponse<JobSummary>> {
102	  const params = new URLSearchParams({
103	    page: page.toString(),
104	    page_size: pageSize.toString(),
105	  });
106	  if (filters?.search) {
107	    params.set("q", filters.search);
108	  }
109	  if (filters?.agents) {
110	    for (const agent of filters.agents) {
111	      params.append("agent", agent);
112	    }
113	  }
114	  if (filters?.providers) {
115	    for (const provider of filters.providers) {
116	      params.append("provider", provider);
117	    }
118	  }
119	  if (filters?.models) {
120	    for (const model of filters.models) {
121	      params.append("model", model);
122	    }
123	  }
124	  if (filters?.dates) {
125	    for (const date of filters.dates) {
126	      params.append("date", date);
127	    }
128	  }
129	  const response = await fetch(`${API_BASE}/api/jobs?${params}`);
130	  if (!response.ok) {
131	    throw new Error(`Failed to fetch jobs: ${response.statusText}`);
132	  }
133	  return response.json();
134	}
