486	export async function uploadJob(
487	  jobName: string,
488	  visibility?: UploadVisibility
489	): Promise<UploadJobResult> {
490	  const response = await fetch(
491	    `${API_BASE}/api/jobs/${encodeURIComponent(jobName)}/upload`,
492	    {
493	      method: "POST",
494	      headers: { "Content-Type": "application/json" },
495	      body: JSON.stringify({ visibility: visibility ?? null }),
496	    }
497	  );
498	  if (!response.ok) {
499	    let detail = response.statusText;
500	    try {
501	      const data = await response.json();
502	      if (data?.detail) detail = data.detail;
503	    } catch {
504	      // response wasn't JSON; fall back to statusText
505	    }
506	    throw new Error(detail);
507	  }
508	  return response.json();
509	}
